import { Component } from "react";
class Message extends Component{
    constructor(){
        super();
        this.state={
            Message:"This hase to be Done Properly"
        }
    }
    render(){
        <button></button>
        return <h2>This is Statefull {this.state.Message}</h2>
    }
}
export default Message
